        raise ValueError("n must be a non-negative integer")
    if n == 0:
        return 1
    if n == 1:
        return 1

    # Bell triangle method
    # Start with row 0: 1
    # Each row starts with the last element of the previous row
    # Each element is the sum of the two elements above it (diagonal and left)

    prev_row = [1]

    while len(prev_row) <= n:
        current_row = [prev_row[-1]]
        for i in range(len(prev_row) - 1):
            current_row.append(prev_row[i] + prev_row[i + 1])
        prev_row = current_row

    return prev_row[n]

